def factorize(n: int) -> List[int]:
    factors = []
    d = 2
    while d * d <= n:
        while (n % d) == 0:
            factors.append(d)
            n //= d
        d += 1
    if n > 1:
        factors.append(n)
    return factors

def remove_duplicates(numbers: List[int]) -> List[int]:
    seen = set()
    duplicates = set()
    result = []
    for num in numbers:
        if num in seen:
            duplicates.add(num)
        else:
            seen.add(num)
            result.append(num)
    for num in numbers:
        if num not in duplicates:
            result.append(num)
    return result

def is_prime(n):
    if n <= 1:
        return False
    if n <= 3:
        return True
    if n % 2 == 0 or n % 3 == 0:
        return False
    i = 5
    while i * i <= n:
        if n % i == 0 or n % (i + 2) == 0:
            return False
        i += 6
    return True

def find_zero(xs: list):
    if len(xs) % 2 != 0:
        raise ValueError("Coefficients list must have an even number of elements.")
    max_coeff = max(xs)
    if max_coeff == 0:
        raise ValueError("The largest coefficient must be non-zero.")
    from scipy.optimize import fsolve
    def poly(x):
        return sum(c * x**i for i, c in enumerate(xs))
    zero = fsolve(poly, 0.0)[0]
    return round(zero, 10)

