def car_race_collision(n: int):
    left_cars = [i for i in range(n)]
    right_cars = [i for i in range(n, 2 * n)]
    collisions = 0
    for l in left_cars:
        for r in right_cars:
            if l < r:
                collisions += 1
    return collisions

